import re
import math

raw_input = r"""
QUESTION:
{question}

DENSE_RESULTS:
{dense_results}

ALL_CHUNKS:
{all_chunks}
"""

question = ""
dense_raw = ""
all_chunks_raw = ""

if "QUESTION:" in raw_input:
    part = raw_input.split("QUESTION:", 1)[1]
    if "DENSE_RESULTS:" in part:
        question = part.split("DENSE_RESULTS:", 1)[0].strip()

if "DENSE_RESULTS:" in raw_input:
    part = raw_input.split("DENSE_RESULTS:", 1)[1]
    if "ALL_CHUNKS:" in part:
        dense_raw = part.split("ALL_CHUNKS:", 1)[0].strip()

if "ALL_CHUNKS:" in raw_input:
    all_chunks_raw = raw_input.split("ALL_CHUNKS:", 1)[1].strip()

all_chunks = list()
dense_chunks = list()

for raw_source, target_list in [
    [all_chunks_raw, all_chunks],
    [dense_raw, dense_chunks]
]:
    raw = str(raw_source or "").replace("\\n", "\n").replace("<br/>", "\n").strip()
    lines = raw.splitlines()
    parts = list()
    current = list()

    for line in lines:
        line = line.strip()

        if not line:
            if current:
                parts.append(" ".join(current))
                current = list()
            continue

        if line.startswith("|:"):
            continue

        current.append(line)

    if current:
        parts.append(" ".join(current))

    if len(parts) == 0 and len(raw) > 0:
        parts = [raw]

    seen = set()

    for part in parts:
        part = str(part).strip()

        for ch in ["[", "]", "'", '"', ",", "|"]:
            part = part.replace(ch, " ")

        part = part.replace(chr(123), " ")
        part = part.replace(chr(125), " ")
        part = re.sub(r"\s+", " ", part).strip()

        if len(part) > 10 and not part.lower().startswith("text file_path"):
            key = part[:160].lower()
            if key not in seen:
                seen.add(key)
                target_list.append(part)

if len(all_chunks) == 0:
    all_chunks = dense_chunks[:]

q_tokens = re.findall(r"[a-zA-ZÀ-ÿ0-9_]+", str(question).lower())

stop = set([
    "le", "la", "les", "un", "une", "des", "de", "du",
    "ce", "c", "est", "que", "quoi", "qu", "dans",
    "sur", "pour", "et", "ou", "a", "au"
])

q_tokens = [t for t in q_tokens if t not in stop]

dense_ranked = list()

for i, txt in enumerate(dense_chunks[:15], start=1):
    dense_ranked.append(dict(id="D" + str(i), text=txt, rank=i, source="dense"))

bm25_ranked = list()

for txt in all_chunks:
    tokens = re.findall(r"[a-zA-ZÀ-ÿ0-9_]+", str(txt).lower())
    score = 0

    for q in q_tokens:
        tf = tokens.count(q)
        if tf:
            score = score + 1 + math.log(1 + tf)

    if score > 0:
        bm25_ranked.append(dict(id="B" + str(len(bm25_ranked) + 1), text=txt, score=score, source="bm25"))

bm25_ranked = sorted(bm25_ranked, key=lambda x: x["score"], reverse=True)[:15]

for i, item in enumerate(bm25_ranked, start=1):
    item["rank"] = i

scores = dict()
docs = dict()

for result_list in [dense_ranked, bm25_ranked]:
    for rank, doc in enumerate(result_list, start=1):
        key = re.sub(r"\s+", " ", str(doc["text"]).lower()).strip()[:180]
        scores[key] = scores.get(key, 0) + 1 / (60 + rank)

        if key not in docs:
            docs[key] = doc

fused = list()

for key, score in scores.items():
    item = dict(docs[key])
    item["rrf_score"] = score
    fused.append(item)

fused = sorted(fused, key=lambda x: x["rrf_score"], reverse=True)[:20]

reranked = list()

for doc in fused:
    chunk_tokens = set(re.findall(r"[a-zA-ZÀ-ÿ0-9_]+", str(doc["text"]).lower()))
    query_tokens = set(q_tokens)

    lexical = len(query_tokens & chunk_tokens) / max(1, len(query_tokens))

    bonus = 0.0
    lower_chunk = str(doc["text"]).lower()

    for term in q_tokens:
        if len(term) > 3 and term in lower_chunk:
            bonus = bonus + 0.05

    doc["cross_encoder_score"] = lexical + bonus
    reranked.append(doc)

reranked = sorted(
    reranked,
    key=lambda x: (x.get("cross_encoder_score", 0), x.get("rrf_score", 0)),
    reverse=True
)[:5]

context = "\n\n---\n\n".join([d["text"] for d in reranked])

if not context.strip():
    context = "Aucun contexte pertinent trouvé dans les documents."

print(context)

